// The original implant path is designed for approximately 51x72 viewBox
// Path coordinates: X range ~9-42 (center ~25.5), Y range ~1-71
const IMPLANT_PATH = `M11.148 65.3107C10.6586 65.3107 9.8057 68.5011 9.1496 69.5682C8.77948 70.1702 9.25672 70.9175 9.89375 70.9937C9.964 71.0021 10.0343 70.9926 10.1036 70.978C11.1367 70.7604 19.6742 69 25.5 69C31.3326 69 39.9995 70.7645 41.0303 70.9788C41.0986 70.993 41.1672 71.0021 41.2365 70.9937C41.8615 70.9178 42.2206 70.1703 41.8504 69.5682C41.1943 68.5011 40.3413 65.3107 39.852 65.3107M11.148 65.3107C11.8082 65.3107 11.5367 62.8388 11.2513 61.1997C11.1907 60.8517 11.2835 60.4912 11.5074 60.2404M11.148 65.3107H39.852M11.5074 60.2404L12.3823 59.2603C12.4839 59.1464 12.5605 59.0076 12.606 58.8548L13.3319 56.4153C13.4152 56.1353 13.3881 55.8289 13.2574 55.5726M11.5074 60.2404H39.4926M13.2574 55.5726L11.706 52.5312C11.6433 52.4083 11.5587 52.301 11.4576 52.2161L10.5497 51.4532M13.2574 55.5726H37.7426M10.5497 51.4532C10.1216 51.0936 10.054 50.4035 10.4022 49.9484L12.0804 47.7551M10.5497 51.4532H40.4503M12.0804 47.7551C12.3503 47.4023 12.3779 46.8914 12.1478 46.5047L12.0968 46.419C11.8242 45.961 11.9185 45.3442 12.3117 45.0139L12.4751 44.8765C12.969 44.4616 12.969 43.6318 12.4751 43.2169M12.0804 47.7551H38.9196M12.4751 43.2169L10.8394 41.8425C10.319 41.4054 10.3526 40.5193 10.9042 40.1331L13.0276 38.6464M12.4751 43.2169H38.5249M13.0276 38.6464C13.2983 38.4569 13.4628 38.1244 13.4628 37.7668V34.7113C13.4628 34.3848 13.3256 34.0773 13.0924 33.8815M13.0276 38.6464H37.9724M13.0924 33.8815L10.7467 31.9106C10.2529 31.4957 10.2529 30.6659 10.7467 30.251M13.0924 33.8815H37.9076M10.7467 30.251L13.0924 28.2802C13.3256 28.0843 13.4628 27.7769 13.4628 27.4504V25.9557M10.7467 30.251H40.2533M10.9576 20.7384L13.0924 18.9448C13.3256 18.7489 13.4628 18.4414 13.4628 18.115V15.0594M10.9576 20.7384C10.4069 21.201 10.4834 22.1511 11.0991 22.496L12.951 23.5332C13.2646 23.7089 13.4628 24.0681 13.4628 24.461V25.9557M10.9576 20.7384H40.0424M13.4628 15.0594C13.4628 14.7018 13.2983 14.3694 13.0276 14.1798L10.7461 12.5824C10.2411 12.2289 10.161 11.441 10.5821 10.9693M13.4628 15.0594H37.5372M1