// Original implant dimensions (from the path coordinates)
const IMPLANT_WIDTH = 51
const IMPLANT_HEIGHT = 72

// Parse viewBox to get tooth dimensions
const toothDimensions = computed(() => {
  const parts = props.viewBox.split(' ').map(Number)
  return {
    width: parts[2] || 60,
    height: parts[3] || 130
  }
})

// Calculate transform to position and scale the implant within the tooth's root area
const implantTransform = computed(() => {
  const { width, height } = toothDimensions.value

  // Root area is roughly the top 70% of the tooth viewBox
  // We want to position the implant to fill most of this area
  const rootAreaTop = height * 0.02
  const rootAreaBottom = height * 0.70
  const rootAreaHeight = rootAreaBottom - rootAreaTop

  // Calculate scale to fit the implant in the root area
  // Scale based on height, maintaining aspect ratio
  const scale = rootAreaHeight / IMPLANT_HEIGHT

  // Center the implant horizontally
  const scaledWidth = IMPLANT_WIDTH * scale
  const translateX = (width - scaledWidth) / 2

  // Position at the top of the root area
  const translateY = rootAreaTop

  return `translate(${translateX}, ${translateY}) scale(${scale})`
})

// Get status styling
const statusStyle = computed(() => STATUS_STYLES[props.status] || STATUS_STYLES.existing)
</script>

<template>
  <g
    class="dental-implant"
    :transform="implantTransform"
  >
    <!-- Implant screw path - uses same stroke as tooth roots -->
    <path
      :d="IMPLANT_PATH"
      class="implant-stroke"
      fill="none"
      stroke-width="0.6"
      vector-effect="non-scaling-stroke"
      stroke-linejoin="round"
      :opacity="statusStyle.opacity"
    />

    <!-- Fill for the implant body (subtle background) -->
    <path
      :d="IMPLANT_PATH"
      :fill="fill"
      fill-opacity="0.15"
      stroke="none"
    />
  </g>
</template>

<style scoped>
